#include <bits/stdc++.h>
using namespace std;
bool sieve_of_eratosthenes(int n) {
    vector<bool> primes(n + 1, true);
    primes[0] = primes[1] = false;
    for (int p = 2; p * p <= n; p++) {
        if (primes[p]) {
            for (int i = p * p; i <= n; i += p)
                primes[i] = false;
        }
    }
    return true;
}
int main() {
    int count;
    cin >> count;
    long long L, R;
    cin >> L >> R;
    vector<bool> primes(R + 1, true);
    primes[0] = primes[1] = false;
    for (int p = 2; p * p <= R; p++) {
        if (primes[p]) {
            for (int i = p * p; i <= R; i += p)
                primes[i] = false;
        }
    }
    int count_primes = 0;
    for (int i = L; i <= R; i++) {
        if (primes[i]) count_primes++;
    }
    cout << 1 << '\n' << count_primes << '\n';
    return 0;
}
